import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"曹雪芹故居纪念馆","description":"","frontmatter":{},"headers":[],"relativePath":"history/cao-xueqin-residence.md","filePath":"history/cao-xueqin-residence.md","lastUpdated":1784773307000}'),n={name:"history/cao-xueqin-residence.md"};function d(i,t,o,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="曹雪芹故居纪念馆" tabindex="-1">曹雪芹故居纪念馆 <a class="header-anchor" href="#曹雪芹故居纪念馆" aria-label="Permalink to &quot;曹雪芹故居纪念馆&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1583977393611-885b3e5cc701?w=1200" alt="曹雪芹故居"></p><blockquote><p>&quot;满纸荒唐言，一把辛酸泪。都云作者痴，谁解其中味？&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>曹雪芹故居纪念馆位于北京市东城区广渠门内大街207号（蒜市口街16号），是伟大文学家曹雪芹晚年居住的地方。在这里，曹雪芹经历了从锦衣玉食到举家食粥的巨变，以&quot;字字看来皆是血，十年辛苦不寻常&quot;的精神，创作了中国古典小说的巅峰之作《红楼梦》。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:00（周二至周日），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1小时</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁7号线广渠门内站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区广渠门内大街207号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="曹家兴衰" tabindex="-1">曹家兴衰 <a class="header-anchor" href="#曹家兴衰" aria-label="Permalink to &quot;曹家兴衰&quot;">​</a></h3><p>曹雪芹（约1715-1763），名霑，字梦阮，号雪芹。其家族为清代内务府正白旗包衣出身，曾祖曹玺、祖父曹寅、父曹頫三代世袭江宁织造，家世显赫。康熙南巡时，曹家曾四次接驾，富贵至极。</p><h4 id="家道中落" tabindex="-1">家道中落 <a class="header-anchor" href="#家道中落" aria-label="Permalink to &quot;家道中落&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1728年</td><td style="text-align:left;">曹頫获罪抄家，举家迁回北京</td></tr><tr><td style="text-align:left;">1730年代</td><td style="text-align:left;">曹雪芹少年时期，家道逐渐中落</td></tr><tr><td style="text-align:left;">1740年代</td><td style="text-align:left;">曹雪芹居住于蒜市口，开始创作《红楼梦》</td></tr><tr><td style="text-align:left;">1763年</td><td style="text-align:left;">曹雪芹病逝于北京西山</td></tr></tbody></table><h3 id="蒜市口故居" tabindex="-1">蒜市口故居 <a class="header-anchor" href="#蒜市口故居" aria-label="Permalink to &quot;蒜市口故居&quot;">​</a></h3><p>乾隆年间，曹雪芹家从南京迁回北京后，居于崇文门外蒜市口一带。据考证，广渠门内大街207号院即为曹雪芹晚年居住地之一。此处靠近崇文门，交通便利，周边商业繁荣，是当年普通旗人居住的区域。</p><h2 id="故居布局" tabindex="-1">故居布局 <a class="header-anchor" href="#故居布局" aria-label="Permalink to &quot;故居布局&quot;">​</a></h2><h3 id="院落结构" tabindex="-1">院落结构 <a class="header-anchor" href="#院落结构" aria-label="Permalink to &quot;院落结构&quot;">​</a></h3><p>曹雪芹故居是一座典型的老北京四合院，虽然规模不大，但布局规整，体现了清代普通旗人的居住特点。</p><h4 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">功能</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大门</strong></td><td style="text-align:left;">入口</td><td style="text-align:left;">传统如意门</td></tr><tr><td style="text-align:left;"><strong>影壁</strong></td><td style="text-align:left;">照壁</td><td style="text-align:left;">砖雕影壁</td></tr><tr><td style="text-align:left;"><strong>正房</strong></td><td style="text-align:left;">展室</td><td style="text-align:left;">曹雪芹生平展</td></tr><tr><td style="text-align:left;"><strong>东厢房</strong></td><td style="text-align:left;">展室</td><td style="text-align:left;">《红楼梦》创作展</td></tr><tr><td style="text-align:left;"><strong>西厢房</strong></td><td style="text-align:left;">展室</td><td style="text-align:left;">曹家兴衰展</td></tr><tr><td style="text-align:left;"><strong>后院</strong></td><td style="text-align:left;">庭院</td><td style="text-align:left;">复原清代民居场景</td></tr></tbody></table><h3 id="主要展室" tabindex="-1">主要展室 <a class="header-anchor" href="#主要展室" aria-label="Permalink to &quot;主要展室&quot;">​</a></h3><h4 id="曹雪芹生平展-正房" tabindex="-1">曹雪芹生平展（正房） <a class="header-anchor" href="#曹雪芹生平展-正房" aria-label="Permalink to &quot;曹雪芹生平展（正房）&quot;">​</a></h4><p>展示曹雪芹从锦衣玉食的公子到举家食粥的寒士，最终在西山著书的人生历程。</p><ul><li><strong>江宁织造时期</strong>：曹家显赫的江南岁月</li><li><strong>北京落魄时期</strong>：家道中落后的北京生活</li><li><strong>西山著书时期</strong>：创作《红楼梦》的艰苦岁月</li></ul><h4 id="《红楼梦》创作展-东厢房" tabindex="-1">《红楼梦》创作展（东厢房） <a class="header-anchor" href="#《红楼梦》创作展-东厢房" aria-label="Permalink to &quot;《红楼梦》创作展（东厢房）&quot;">​</a></h4><p>展示《红楼梦》的创作背景、版本流传以及研究情况。</p><ul><li><strong>创作背景</strong>：从生活到艺术的升华</li><li><strong>早期抄本</strong>：甲戌本、己卯本、庚辰本等珍贵抄本介绍</li><li><strong>研究历史</strong>：红学发展的百年历程</li></ul><h4 id="曹家兴衰展-西厢房" tabindex="-1">曹家兴衰展（西厢房） <a class="header-anchor" href="#曹家兴衰展-西厢房" aria-label="Permalink to &quot;曹家兴衰展（西厢房）&quot;">​</a></h4><p>展示曹家从显赫到衰落的历史，以及这段经历对曹雪芹创作的影响。</p><h2 id="珍贵文物" tabindex="-1">珍贵文物 <a class="header-anchor" href="#珍贵文物" aria-label="Permalink to &quot;珍贵文物&quot;">​</a></h2><h3 id="文献资料" tabindex="-1">文献资料 <a class="header-anchor" href="#文献资料" aria-label="Permalink to &quot;文献资料&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>《红楼梦》抄本</strong></td><td style="text-align:left;">各种版本的《红楼梦》</td></tr><tr><td style="text-align:left;"><strong>曹家档案</strong></td><td style="text-align:left;">江宁织造档案复制品</td></tr><tr><td style="text-align:left;"><strong>曹雪芹画像</strong></td><td style="text-align:left;">相传为曹雪芹的画像</td></tr><tr><td style="text-align:left;"><strong>研究著作</strong></td><td style="text-align:left;">红学研究的重要著作</td></tr></tbody></table><h3 id="场景复原" tabindex="-1">场景复原 <a class="header-anchor" href="#场景复原" aria-label="Permalink to &quot;场景复原&quot;">​</a></h3><ul><li><strong>书房场景</strong>：复原曹雪芹创作《红楼梦》的书房</li><li><strong>生活场景</strong>：复原清代普通旗人的居家生活</li><li><strong>市井场景</strong>：复原崇文门外的市井风貌</li></ul><h2 id="《红楼梦》与北京" tabindex="-1">《红楼梦》与北京 <a class="header-anchor" href="#《红楼梦》与北京" aria-label="Permalink to &quot;《红楼梦》与北京&quot;">​</a></h2><h3 id="创作背景" tabindex="-1">创作背景 <a class="header-anchor" href="#创作背景" aria-label="Permalink to &quot;创作背景&quot;">​</a></h3><p>《红楼梦》虽然以江宁织造曹家的生活为原型，但曹雪芹在北京的生活经历对创作产生了深远影响。书中描写的贵族生活、人情冷暖、世态炎凉，无不渗透着他在北京的生活感悟。</p><h3 id="北京元素" tabindex="-1">北京元素 <a class="header-anchor" href="#北京元素" aria-label="Permalink to &quot;北京元素&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">书中描写</th><th style="text-align:left;">北京元素</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>荣国府、宁国府</strong></td><td style="text-align:left;">北京王府建筑</td></tr><tr><td style="text-align:left;"><strong>大观园</strong></td><td style="text-align:left;">北京园林艺术</td></tr><tr><td style="text-align:left;"><strong>节庆风俗</strong></td><td style="text-align:left;">北京民俗风情</td></tr><tr><td style="text-align:left;"><strong>饮食服饰</strong></td><td style="text-align:left;">清代北京生活</td></tr></tbody></table><h3 id="红楼-文化" tabindex="-1">&quot;红楼&quot;文化 <a class="header-anchor" href="#红楼-文化" aria-label="Permalink to &quot;&quot;红楼&quot;文化&quot;">​</a></h3><p>《红楼梦》不仅是一部文学巨著，更是一部清代社会的百科全书。从建筑园林到饮食服饰，从诗词歌赋到医药养生，无所不包。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约1小时）</strong>：</p><p>入口 → 影壁 → 正房（曹雪芹生平展） → 东厢房（《红楼梦》创作展） → 西厢房（曹家兴衰展） → 后院（场景复原） → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：建议提前在官网或电话预约</li><li><strong>最佳时间</strong>：工作日人较少，适合慢慢参观</li><li><strong>拍照位置</strong>：影壁、书房复原场景都是绝佳拍照点</li><li><strong>讲解服务</strong>：可以租用讲解器，了解更多红学知识</li><li><strong>周边游览</strong>：参观完后可以到前门、天坛游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">7号线广渠门内站B口，步行约5分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">23、57、715路广渠门内站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;曹雪芹故居纪念馆&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">前门大街</td><td style="text-align:center;">约1公里</td><td style="text-align:left;">老北京商业街</td></tr><tr><td style="text-align:left;">天坛</td><td style="text-align:center;">约2公里</td><td style="text-align:left;">皇家祭祀建筑</td></tr><tr><td style="text-align:left;">崇文门</td><td style="text-align:center;">约500米</td><td style="text-align:left;">老北京城门</td></tr><tr><td style="text-align:left;">明城墙遗址</td><td style="text-align:center;">约1公里</td><td style="text-align:left;">古城墙遗址</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>曹雪芹是中国文学史上最伟大的作家之一，《红楼梦》与《三国演义》《水浒传》《西游记》并称中国四大古典名著，且被公认为艺术成就最高。</p><p>&quot;开谈不说《红楼梦》，读尽诗书也枉然。&quot;《红楼梦》不仅在文学上达到了巅峰，更深刻影响了中国的文化、艺术和思想。</p><h3 id="红学传承" tabindex="-1">红学传承 <a class="header-anchor" href="#红学传承" aria-label="Permalink to &quot;红学传承&quot;">​</a></h3><p>自《红楼梦》问世以来，研究《红楼梦》的学问被称为&quot;红学&quot;，成为一门专门的学科。从脂砚斋到俞平伯、周汝昌，一代代学者前赴后继，探寻这部巨著的秘密。</p><hr><p><strong>📍 地址</strong>：北京市东城区广渠门内大街207号 <strong>🚇 地铁</strong>：7号线广渠门内站B口 <strong>📞 电话</strong>：010-67135148</p><p><strong>💡 Tips</strong>：曹雪芹故居规模不大，但意义非凡。建议与《红楼梦》原著对照参观，更能体会&quot;字字看来皆是血&quot;的创作艰辛。故居周边的前门、天坛等景点可以安排在同一天游览。</p>',58)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
